var e=[{id:`L2_1`,type:`dialog`,speaker:`WIND_VARUNA_NULL_NULL`,text:{KOREA:`저는 쓰러진 동료들을 대신해 앞으로 나아가야 해요.`,JPN:`私は倒れていった仲間たちに代わって、前に進まなければなりません。`,ENG:`I'm going to move forward on behalf of my fallen comrades.`,TWN:`我必須代替倒下的夥伴往前，`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`WIND_VARUNA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`WIND_VARUNA_NULL_NULL`,text:{KOREA:`관리자님은 제 바람을 이루어줄 수 있으신가요? 그렇다면 최선을 다해 당신을 돕도록 하겠습니다.`,JPN:`管理者様が私の望みを叶えてくださるなら、私は最善を尽くしてあなたにお力添えいたします。`,ENG:`Will you also make my wish come true, Administrator? If so, then I'll do my best to help you.`,TWN:`管理者，你可以實現我的心願嗎？那我也願意盡全力幫助你。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`WIND_VARUNA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};